// Collect outputs from both Notion and Jira nodes
const notionData = $('Notion — Get All RC1 Tasks').first().json;
let jiraItems = [];
try {
  jiraItems = $('Jira — Get This Week\'s Updates').all();
} catch(e) {
  jiraItems = [];
}

// Process Notion pages — filter to RC1-31 epic only
const pages = notionData.results || [];
const rc1Pages = pages.filter(p => {
  const epic = p.properties?.Epic?.rich_text?.[0]?.plain_text;
  return epic === 'RC1-31';
});

const taskSummary = rc1Pages.map(p => {
  const props = p.properties || {};
  return {
    name: props.Name?.title?.[0]?.plain_text || 'Untitled',
    jiraKey: props['Jira Key']?.rich_text?.[0]?.plain_text || '',
    status: props.Status?.select?.name || 'Unknown',
    priority: props.Priority?.select?.name || 'Unknown',
    assignee: props.Assignee?.rich_text?.[0]?.plain_text || 'Unassigned'
  };
});

// Group by status
const done = taskSummary.filter(t => t.status === 'Done');
const inProgress = taskSummary.filter(t => t.status === 'In Progress');
const inReview = taskSummary.filter(t => t.status === 'In Review');
const toDo = taskSummary.filter(t => t.status === 'To Do');
const blocked = taskSummary.filter(t => t.status === 'Blocked');

// Weekly Jira updates
const weeklyUpdates = jiraItems.map(i => ({
  key: i.json.key,
  summary: i.json.fields?.summary,
  status: i.json.fields?.status?.name,
  assignee: i.json.fields?.assignee?.displayName || 'Unassigned'
}));

// Health
const total = taskSummary.length;
const doneCount = done.length;
const completionPct = total > 0 ? Math.round((doneCount / total) * 100) : 0;
let health = '🟢 On Track';
if (blocked.length > 0) health = '🔴 At Risk';
else if (completionPct < 50 && inProgress.length === 0) health = '🟡 Needs Attention';

// Table styles
const tableStyle = 'border-collapse:collapse;width:100%;margin-bottom:24px;font-family:Arial,sans-serif;font-size:13px;';
const thStyle = 'background:#4472C4;color:white;padding:10px 12px;text-align:left;font-weight:600;';
const tdStyle = 'padding:8px 12px;border-bottom:1px solid #e0e0e0;vertical-align:top;';
const tdAltStyle = 'padding:8px 12px;border-bottom:1px solid #e0e0e0;background:#f5f8ff;vertical-align:top;';

// Build HTML table helper
function buildTable(title, emoji, rows) {
  if (rows.length === 0) return '';
  let html = `<h3 style="color:#2c3e50;margin-top:24px;">${emoji} ${title}</h3>`;
  html += `<table style="${tableStyle}">`;
  html += `<tr><th style="${thStyle}">Ticket</th><th style="${thStyle}">Description</th><th style="${thStyle}">Priority</th><th style="${thStyle}">Assignee</th></tr>`;
  rows.forEach((r, i) => {
    const td = i % 2 === 0 ? tdStyle : tdAltStyle;
    const jiraUrl = `https://hirereidcollins.atlassian.net/browse/${r.jiraKey}`;
    html += `<tr>
      <td style="${td}"><a href="${jiraUrl}" style="color:#4472C4;text-decoration:none;">${r.jiraKey}</a></td>
      <td style="${td}">${r.name}</td>
      <td style="${td}">${r.priority}</td>
      <td style="${td}">${r.assignee}</td>
    </tr>`;
  });
  html += '</table>';
  return html;
}

// Build full tables HTML
const tablesHtml = [
  buildTable('In Progress', '🔄', inProgress),
  buildTable('In Review', '👀', inReview),
  buildTable('Blocked', '🚫', blocked),
  buildTable('Up Next', '📋', toDo),
  buildTable('Completed This Week', '✅', done)
].join('');

const reportDate = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

return [{
  json: {
    health,
    completionPct,
    total,
    doneCount,
    inProgressCount: inProgress.length,
    inReviewCount: inReview.length,
    blockedCount: blocked.length,
    toDoCount: toDo.length,
    tablesHtml,
    reportDate,
    weeklyUpdates
  }
}];

