const response = $input.first().json;
let text = response.content?.find(b => b.type === 'text')?.text || '';

// Strip markdown fences
text = text.replace(/^```html\n?/i, '').replace(/```$/i, '').trim();

// Extract subject
const subjectMatch = text.match(/SUBJECT:\s*(.+?)(\n|<)/);
const subject = subjectMatch ? subjectMatch[1].trim() : 'AI Incident Summarizer — Weekly Status Update';

// Extract executive summary HTML (everything after the SUBJECT line)
const execSummary = text.replace(/SUBJECT:\s*.+?(\n|(?=<))/, '').trim();

// Get pre-built tables from Aggregate node
const tablesHtml = $('Aggregate & Summarize Data').first().json.tablesHtml;
const reportDate = $('Aggregate & Summarize Data').first().json.reportDate;
const health = $('Aggregate & Summarize Data').first().json.health;
const completionPct = $('Aggregate & Summarize Data').first().json.completionPct;
const doneCount = $('Aggregate & Summarize Data').first().json.doneCount;
const total = $('Aggregate & Summarize Data').first().json.total;

// Build full email
const htmlBody = `
<div style="font-family:Arial,sans-serif;max-width:800px;margin:0 auto;padding:24px;">
  <h1 style="color:#2c3e50;border-bottom:2px solid #4472C4;padding-bottom:8px;">
    AI Incident Summarizer — Weekly Status Report
  </h1>
  <p style="color:#666;font-size:12px;">Week ending ${reportDate}</p>

  ${execSummary}

  <h2 style="color:#2c3e50;margin-top:32px;">Project Status</h2>
  <table style="border-collapse:collapse;width:100%;margin-bottom:24px;">
    <tr>
      <td style="padding:12px;background:#f5f5f5;border:1px solid #e0e0e0;width:33%;">
        <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:1px;">Overall Health</div>
        <div style="font-size:20px;font-weight:600;margin-top:4px;">${health}</div>
      </td>
      <td style="padding:12px;background:#f5f5f5;border:1px solid #e0e0e0;width:33%;">
        <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:1px;">Completion</div>
        <div style="font-size:20px;font-weight:600;margin-top:4px;">${completionPct}%</div>
        <div style="font-size:12px;color:#888;">${doneCount} of ${total} tickets closed</div>
      </td>
      <td style="padding:12px;background:#f5f5f5;border:1px solid #e0e0e0;width:33%;">
        <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:1px;">Report Date</div>
        <div style="font-size:14px;font-weight:600;margin-top:4px;">${reportDate}</div>
      </td>
    </tr>
  </table>

  ${tablesHtml}

  <p style="margin-top:32px;font-size:13px;color:#444;">
    Best regards,<br>
    <strong>Reid Collins</strong><br>
    Senior Technical Program Manager
  </p>
  <p style="font-size:11px;color:#aaa;border-top:1px solid #eee;padding-top:8px;margin-top:16px;">
    This report was generated automatically by n8n + Claude AI
  </p>
</div>
`;

return [{ json: { subject, body: htmlBody, htmlBody } }];

const error = $input.first().json;
return [{
  json: {
    message: `⚠️ Stakeholder status email failed\nError: ${error.execution?.error?.message || 'Unknown error'}\nTime: ${new Date().toISOString()}`
  }
}];

